            }),
      ), // This trailing comma makes auto-formatting nicer for build methods.
    );
  }

  void _keyEvent(RawKeyEvent key) {
    print('${key.physicalKey} => ${key.logicalKey}');
    if (key.runtimeType.toString() == 'RawKeyDownEvent') {
      (_keyTime.isRunning) ? _keyTime.reset() : _keyTime.start();
      if (_keyTime.elapsedMilliseconds < _barTime) {
        var keyname = key.logicalKey.keyLabel;
        _barCode += keyname;
        if (_barTimer == null) {
          _barTimer = Timer(
              Duration(milliseconds: _barTime), () => _barProcessor(_barCode));
        } else {
          _barTimer!.cancel();
          _barTimer = Timer(
              Duration(milliseconds: _barTime), () => _barProcessor(_barCode));
        }
      }
    }
  }

  void _barProcessor(String barcode) {
    var userId = RegExp(r'\d{5,}').firstMatch(barcode)?.group(0) ?? '';
    if (userId.isNotEmpty) {
      setState(() {
        userIdText = userId;
      });
      print("userId=$userId");
      // ...
    }
    _keyTime.stop();
    _barCode = '';
  }
}
